+        assert_eq!(errors.len(), 1);
+        assert!(errors[0].contains("data_hash"));
+    }
+
+    #[test]
+    fn validate_version_envelope_checks_format() {
+        let v = json!({
+            "generated_at": "2026-03-04T07:00:00Z",
+            "data_hash": "abc123",
+            "output_format": "json",
