+        assert_eq!(diffs.len(), 1);
+        assert!(matches!(diffs[0].kind, DiffKind::ValueMismatch { .. }));
+        assert_eq!(diffs[0].path, "x");
+    }
+
+    #[test]
+    fn compare_json_detects_missing_field() {
+        let a = json!({"x": 1, "y": 2});
